(self.webpackChunkvuepress_blog=self.webpackChunkvuepress_blog||[]).push([[919],{5076:(l,e,i)=>{"use strict";i.r(e),i.d(e,{data:()=>a});const a={key:"v-f6da1ed4",path:"/pages/fe-interview/h5LoadSpeedOptimize/",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"性能优化清单",slug:"性能优化清单",children:[{level:3,title:"raf(requestAnimationFrame) 加载js",slug:"raf-requestanimationframe-加载js",children:[]},{level:3,title:"online事件触发全局图片重试",slug:"online事件触发全局图片重试",children:[]},{level:3,title:"DisableTranslate 禁止翻译",slug:"disabletranslate-禁止翻译",children:[]},{level:3,title:"preloadLinks 预加载链接",slug:"preloadlinks-预加载链接",children:[]},{level:3,title:"smallScroll 流畅滚动",slug:"smallscroll-流畅滚动",children:[]}]}],filePathRelative:"pages/fe-interview/h5LoadSpeedOptimize/README.md",git:{updatedTime:1718804559e3,contributors:[{name:"COOKIES-LGL",email:"1344714332@qq.com",commits:3}]}}},7959:(l,e,i)=>{"use strict";i.r(e),i.d(e,{default:()=>s});const a=(0,i(6252).uE)('<h2 id="性能优化清单"><a class="header-anchor" href="#性能优化清单">#</a> 性能优化清单</h2><p>*** 经典的H5页面加载包含以下过程： ***</p><ul><li>webview初始化</li><li>html加载</li><li>HTTP连接建立</li><li>请求</li><li>html解析和渲染</li><li>解析html</li><li>css/js</li><li>渲染</li><li>解析js</li><li>可交互</li></ul><p>*** 各个过程的优化思路可以归纳为四点： ***</p><ul><li>串行改并行；</li><li>缓存：最大化利用缓存；</li><li>过程提前：能提前执行尽可能提前；</li><li>尽可能缩减每个过程的耗时；</li></ul><p>*** 优化手段 *** 客户端优化</p><ul><li>预创建：提前创建WebView</li><li>预连接：冷启动下提前发起一起请求，预热通道，预创建是前提；</li><li>预请求：Api请求与WebView初始化、html加载并行；</li></ul><p>*** 首屏性能优化 ***</p><details class="custom-container details"><p>目标：尽快让用户看到首屏主要内容，避免白屏等待</p></details><ol><li>ssr方案</li></ol><ul><li>服务端 流式渲染：将html从服务端分块输出，能够缩短首字节和首屏时间，html头部的提前输出能够提前css/js等重要资源的加载 请求并行：首屏依赖的数据接口尽可能并行发出，缩短请求等待时间 分块渲染：针对首屏依赖的慢请求，让其对应的模块先用骨架输出给客户端展示。待慢请求返回后，再生成内联js将真实内容替换骨架。 减少渲染逻辑： 非首屏、纯客户端组件只在客户端渲染，如返回顶部、前往app等组件 商品列表组件减少首屏渲染个数，减少数据量</li><li>客户端 首屏css头部输出，js在首屏后执行（插入在html底部 或 添加defer 或在下一帧插入执行），避免阻塞页面渲染 IOS渲染优化：body顶部添加空白字符优化渲染、js下一帧执行优化图片渲染</li></ul><ol start="2"><li>其他方案</li></ol><ul><li>客户端预渲染预请求：客户端预载不可见webview加载目标页面，待用户真正需要进入时直接展示已加载好的页面内容</li><li>html强缓存：服务端设置强缓存头，让客户端缓存html，后续客户端直接取缓存html渲染并通过js动态更新页面数据。适合首页等场景</li><li>带图加载：将前置页面加载过的图片资源，直接作为后续页面的头图展示，可利用缓存快速展示。适合商详等场景</li><li>Critical CSS：​Critical CSS​</li><li>资源preload：​【资源 Prefetch】端内静态资源预加载 - 高流量页面全覆盖​</li><li>JS分片执行：​JS分片初始化-接入​</li><li>商品图规范：​商品图规范resizeWidth统一​</li><li>JS体积优化：​initial js bundle体积优化​</li></ul><p>*** 可交互时间优化 ***</p><details class="custom-container details"><p>目标：尽快开始响应用户的操作，避免操作无效</p></details><p>加速js加载 cdn 客户端资源包 精简js体积 模块懒加载（可依赖loadable components提供的能力） 非首屏依赖的js模块延迟加载 特定环境、特定条件依赖的js模块可选加载，如风控包可仅在非app环境或app不支持提供风控token的版本才加载 大模块精简：preact替换react，简单场景移除mobx polyfill动态加载：针对ua判断，按需引入polyfill 部署es2015脚本：针对现代浏览器的脚本优化方案 渐进式补水：逐步进行补水，先补水必要的部分（首屏、用户极有可能交互的部分），再根据适当的时机补水其他部分</p><p>*** 交互体验优化 ***</p><details class="custom-container details"><p>目标：尽快给用户操作反馈，避免卡顿，包括tab流畅切换、滚动不掉帧等</p></details><ul><li>图片懒加载：不可见图片进入可视区域才开始加载，避免影响可视区资源加载</li><li>虚拟列表：不在可视范围的内容使其避免渲染，可优化多tab+长列表等场景，</li><li>骨架：异步请求数据未返回之前，可用美丽的骨架进行占位</li><li>回退缓存：html快照实现回退定位，</li><li>视频转.webp动图：加快加载</li><li>tab手势横滑</li></ul><h3 id="raf-requestanimationframe-加载js"><a class="header-anchor" href="#raf-requestanimationframe-加载js">#</a> raf(requestAnimationFrame) 加载js</h3><p><a href="./rafScript">rafScript</a></p><h3 id="online事件触发全局图片重试"><a class="header-anchor" href="#online事件触发全局图片重试">#</a> online事件触发全局图片重试</h3><p><a href="./imagesRetryGuard">imagesRetryGuard</a></p><h3 id="disabletranslate-禁止翻译"><a class="header-anchor" href="#disabletranslate-禁止翻译">#</a> DisableTranslate 禁止翻译</h3><p><a href="./disableTranslate">disableTranslate</a></p><h3 id="preloadlinks-预加载链接"><a class="header-anchor" href="#preloadlinks-预加载链接">#</a> preloadLinks 预加载链接</h3><p><a href="./preloadLinks">preloadLinks</a></p><h3 id="smallscroll-流畅滚动"><a class="header-anchor" href="#smallscroll-流畅滚动">#</a> smallScroll 流畅滚动</h3><p><a href="./smallScroll">smallScroll</a></p>',29),s={render:function(l,e){return a}}}}]);